710: static void
711: mark_aliased_reaching_defs_necessary (gimple *stmt, tree ref)
712: {
713:   /* Should have been caught before calling this function.  */
714:   gcc_checking_assert (!keep_all_vdefs_p ());
715: 
716:   unsigned int chain;
717:   ao_ref refd;
718:   gcc_assert (!chain_ovfl);
719:   ao_ref_init (&refd, ref);
720:   chain = walk_aliased_vdefs (&refd, gimple_vuse (stmt),
721: 			      mark_aliased_reaching_defs_necessary_1,
722: 			      gimple_bb (stmt), NULL);
723:   if (chain > longest_chain)
724:     longest_chain = chain;
725:   total_chain += chain;
726:   nr_walks++;
727: }
