729: /* Worker for the walker that marks reaching definitions of REF, which
730:    is not based on a non-aliased decl.  For simplicity we need to end
731:    up marking all may-defs necessary that are not based on a non-aliased
732:    decl.  The only job of this walker is to skip may-defs based on
733:    a non-aliased decl.  */
734: 
735: static bool
736: mark_all_reaching_defs_necessary_1 (ao_ref *ref ATTRIBUTE_UNUSED,
737: 				    tree vdef, void *data ATTRIBUTE_UNUSED)
738: {
739:   gimple *def_stmt = SSA_NAME_DEF_STMT (vdef);
740: 
741:   /* We have to skip already visited (and thus necessary) statements
742:      to make the chaining work after we dropped back to simple mode.  */
743:   if (chain_ovfl
744:       && bitmap_bit_p (processed, SSA_NAME_VERSION (vdef)))
745:     {
746:       gcc_assert (gimple_nop_p (def_stmt)
747: 		  || gimple_plf (def_stmt, STMT_NECESSARY));
748:       return false;
749:     }
750: 
751:   /* We want to skip stores to non-aliased variables.  */
752:   if (!chain_ovfl
753:       && gimple_assign_single_p (def_stmt))
754:     {
755:       tree lhs = gimple_assign_lhs (def_stmt);
756:       if (!ref_may_be_aliased (lhs))
757: 	return false;
758:     }
759: 
760:   /* We want to skip statments that do not constitute stores but have
761:      a virtual definition.  */
762:   if (gcall *call = dyn_cast <gcall *> (def_stmt))
763:     {
764:       tree callee = gimple_call_fndecl (call);
765:       if (callee != NULL_TREE
766: 	  && fndecl_built_in_p (callee, BUILT_IN_NORMAL))
767: 	switch (DECL_FUNCTION_CODE (callee))
768: 	  {
769: 	  case BUILT_IN_MALLOC:
770: 	  case BUILT_IN_ALIGNED_ALLOC:
771: 	  case BUILT_IN_CALLOC:
772: 	  CASE_BUILT_IN_ALLOCA:
773: 	  case BUILT_IN_STRDUP:
774: 	  case BUILT_IN_STRNDUP:
775: 	  case BUILT_IN_FREE:
776: 	  case BUILT_IN_GOMP_ALLOC:
777: 	  case BUILT_IN_GOMP_FREE:
778: 	    return false;
779: 
780: 	  default:;
781: 	  }
782: 
783:       if (callee != NULL_TREE
784: 	  && (DECL_IS_REPLACEABLE_OPERATOR_NEW_P (callee)
785: 	      || DECL_IS_OPERATOR_DELETE_P (callee))
786: 	  && gimple_call_from_new_or_delete (call))
787: 	return false;
788:       if (is_removable_cxa_atexit_call (call))
789: 	return false;
790:     }
791: 
792:   if (! gimple_clobber_p (def_stmt))
793:     mark_operand_necessary (vdef);
794: 
795:   return false;
796: }
