/* Basic block counter.

   This is a simple GIMPLE optimization pass that counts the number of
   basic blocks in each function and outputs the result to the dump file.

   This pass demonstrates the standard GCC pattern for writing a
   GIMPLE optimization pass:
   1. Define a pass_data struct with metadata
   2. Inherit from gimple_opt_pass
   3. Implement gate() and execute() virtual methods
   4. Register the pass using a make_pass_*() factory function
*/

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "basic-block.h"
#include "dumpfile.h"
#include "function.h"

namespace {

const pass_data pass_data_bb_count =
{
  GIMPLE_PASS, /* type */
  "bb_count", /* name */
  OPTGROUP_NONE, /* optinfo_flags */
  TV_NONE, /* tv_id */
  ( PROP_cfg ), /* properties_required */
  0, /* properties_provided */
  0, /* properties_destroyed */
  0, /* todo_flags_start */
  0, /* todo_flags_finish */
};

class pass_bb_count : public gimple_opt_pass
{
public:
  pass_bb_count (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_bb_count, ctxt)
  {}

  /* opt_pass methods: */
  opt_pass * clone () final override { return new pass_bb_count (m_ctxt); }
  bool gate (function *) final override { return true; }
  unsigned int execute (function *) final override;

}; // class pass_bb_count

unsigned int
pass_bb_count::execute (function *fun)
{
  basic_block bb;
  int bb_count = 0;

  /* Count all basic blocks in the function */
  FOR_EACH_BB_FN (bb, fun)
    {
      bb_count++;
    }

  /* Output the count to the dump file if it exists */
  if (dump_file)
    {
      fprintf (dump_file, "Function %s has %d basic blocks\n",
               function_name (fun), bb_count);
    }

  return 0;
}

} // anon namespace

gimple_opt_pass *
make_pass_bb_count (gcc::context *ctxt)
{
  return new pass_bb_count (ctxt);
}

